queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?challengename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasChallenges ?child ; p:hasContinuity_Coordinators ?parent . } GROUP BY ?child }
  ?child p:ChallengeName ?challengename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Continuity_Coordinators } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?challengename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasChallenges ?child ; p:hasContinuity_Coordinators ?parent . } GROUP BY ?child }
  ?child p:ChallengeName ?challengename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Continuity_Coordinators } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?challengename WHERE {
  ?continuity_coordinators_challenges a :Continuity_Coordinators_Challenges .
  ?challenges a :Challenges .
  ?continuity_coordinators_challenges p:hasChallenges ?challenges .
  ?continuity_coordinators a :Continuity_Coordinators .
  ?continuity_coordinators_challenges p:hasContinuity_Coordinators ?continuity_coordinators .
  ?continuity_coordinators p:name ?name .
  ?challenges p:ChallengeName ?challengename .
} }
}
